import { DeterministicCollector } from './collectors/deterministic';
import { BrowserCollector } from './collectors/browser';
import { NetworkCollector } from './collectors/network';
import { ScreenCollector } from './collectors/screen';
import { WebTelemetryRequest, WebTelemetryConfig } from './types/web-telemetry';
import { WebTelemetryTransformer } from './transformer/web-telemetry-transformer';

const DEFAULT_CONFIG: WebTelemetryConfig = {
  enable_deterministic: true,
  enable_fingerprinting: true,
  enable_trust_assessment: true,
  storage_persistence: 'both',
  trust_thresholds: {
    minimum_trust_score: 0.5,
    automation_sensitivity: 0.8,
    anomaly_tolerance: 0.3
  },
  backend: {
    endpoint: process.env.BACKEND_ENDPOINT || '',
    autoSend: true,
    retryAttempts: 3,
    timeout: 5000,
    headers: {}
  }

};

export class WebTelemetrySDK {
  private config: WebTelemetryConfig;
  private collectors: {
    deterministic: DeterministicCollector;
    browser: BrowserCollector;
    network: NetworkCollector;
    screen: ScreenCollector;
  };

  constructor(config: Partial<WebTelemetryConfig> = {}) {
    this.config = this.mergeWithDefaults(config);
    this.collectors = this.initializeCollectors();

    if (this.config.backend?.autoSend && this.config.backend?.endpoint) {
      this.collectAndSend();
    }
  }

  async collect(): Promise<WebTelemetryRequest> {
    const [deterministic, browser, network, screen] = await Promise.allSettled([
      this.collectors.deterministic.collect(),
      this.collectors.browser.collect(),
      this.collectors.network.collect(),
      this.collectors.screen.collect()
    ]);

    const rawData = {
      deterministic: deterministic.status === 'fulfilled' ? deterministic.value : null,
      browser: browser.status === 'fulfilled' ? browser.value : null,
      network: network.status === 'fulfilled' ? network.value : null,
      screen: screen.status === 'fulfilled' ? screen.value : null
    };

    return WebTelemetryTransformer.toBackendFormat(rawData);
  }

  async collectAndSend(): Promise<{ success: boolean; response?: any; error?: Error }> {
    try {
      const telemetryData = await this.collect();
      const response = await this.sendToBackend(telemetryData);
      return { success: true, response };
    } catch (error) {
      return { success: false, error: error as Error };
    }
  }

  private async sendToBackend(data: WebTelemetryRequest, attempt = 1): Promise<any> {
    const { endpoint, timeout, headers, retryAttempts } = this.config.backend!;

    if (!endpoint) {
      throw new Error('Backend endpoint is not configured.');
    }

    try {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), timeout);
      console.debug(`[DFP] Sending telemetry data to backend (attempt ${attempt})...`, data);
      const response = await fetch(`${endpoint}/api/init`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          ...headers
        },
        body: JSON.stringify(data),
        signal: controller.signal,
        credentials: 'include'
      });

      clearTimeout(timeoutId);

      if (!response.ok) {
        throw new Error(`HTTP ${response.status}: ${response.statusText}`);
      }

      return await response.json();
    } catch (error) {
      if (attempt < (retryAttempts || 1)) {
        await this.delay(1000 * attempt);
        return this.sendToBackend(data, attempt + 1);
      }
      throw error;
    }
  }

  private delay(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms));
  }

  private initializeCollectors() {
    return {
      deterministic: new DeterministicCollector(),
      browser: new BrowserCollector(),
      network: new NetworkCollector(),
      screen: new ScreenCollector()
    };
  }

  private mergeWithDefaults(config: Partial<WebTelemetryConfig>): WebTelemetryConfig {
    return {
      ...DEFAULT_CONFIG,
      ...config,
      trust_thresholds: {
        ...DEFAULT_CONFIG.trust_thresholds,
        ...config.trust_thresholds
      },
      backend: config.backend ? {
        ...DEFAULT_CONFIG.backend,
        ...config.backend
      } : DEFAULT_CONFIG.backend
    };
  }
}

export * from './types/web-telemetry';
export { DeterministicCollector, BrowserCollector, NetworkCollector, ScreenCollector };