import { AbstractCollector } from "../base-collector";

export class SignedTokenCollector extends AbstractCollector<string | null> {
  isAvailable(): boolean {
    return typeof document !== 'undefined' && typeof document.cookie !== 'undefined';
  }

  collect(): string | null {
    try {
      const tokenSources = [
        () => localStorage.getItem('signed_token'),
        () => sessionStorage.getItem('signed_client_token'),
        () => this.getMetaTag('signed-client-token'),
        () => this.getFromHeader('X-Client-Token')
      ]

      for (const getToken of tokenSources) {
        const token = getToken();
        if (token && this.isValidToken(token)) {
          return token;
        }
      }
      return null;
    } catch (error) {
      console.warn('Failed to access localStorage:', error);
      return null;
    }
  }

  private getMetaTag(name: string): string | null {
    const meta = document.querySelector(`meta[name="${name}"]`);
    return meta ? meta.getAttribute('content') : null;
  }

  private getFromHeader(headerName: string): string | null {
    const element = document.querySelector(`[data-header="${headerName}"]`);
    return element ? element.getAttribute(`data-${headerName.toLocaleLowerCase()}`) : null;
  }

  private isValidToken(token: string): boolean {
    try {
      return token.length > 10 && !token.includes(' ') && token.split('.').length >= 2;
    } catch (error) {
      console.warn('Failed to validate token:', error);
      return false;

    }
  }
}