import { AbstractCollector } from "../base-collector";

export class WebAuthnCollector extends AbstractCollector<string | null> {
  isAvailable(): boolean {
    return typeof document !== 'undefined' && typeof document.cookie !== 'undefined';
  }
  private readonly STORAGE_KEY = 'webauthn_credential_id';

  async collect(): Promise<string | null> {
    try {
      if (!window.PublicKeyCredential) {
        console.warn('WebAuthn not supported in this browser.');
        return null;
      }
      const available = await PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable();
      if (!available) {
        console.warn('No platform authenticator available for WebAuthn.');
        return null;
      }
      return localStorage.getItem(this.STORAGE_KEY);
    } catch (error) {
      return null;
    }
  }

  async createCredential(challenge: ArrayBuffer): Promise<string | null> {
    try {
      const credential = await navigator.credentials.create({
        publicKey: {
          challenge,
          rp: { name: 'Device Fingerprint' },
          user: {
            id: new TextEncoder().encode('device-user'),
            name: 'device-user',
            displayName: 'Device User',
          },
          pubKeyCredParams: [{ type: 'public-key', alg: -7 }],
          authenticatorSelection: {
            authenticatorAttachment: 'platform',
            userVerification: 'required',
          },
        },
      }) as PublicKeyCredential;

      if (credential) {
        const credentialId = btoa(String.fromCharCode(...new Uint8Array(credential.rawId)));
        localStorage.setItem(this.STORAGE_KEY, credentialId);
        return credentialId;
      }
      return null;
    } catch (error) {
      console.warn('Failed to create WebAuthn credential:', error);
      return null;
    }
  }
}