import { WebTelemetryRequest, BrowserInfo, DisplayInfo, LocaleInfo, FingerprintInfo, SecuritySignals, NetworkInfo, AppSignals } from '../types/web-telemetry';
import { UAParser } from 'ua-parser-js';

export class WebTelemetryTransformer {
  /**
   * Transform collected data to backend request format
   */
  static async toBackendFormat(collectedData: any): Promise<WebTelemetryRequest> {
    const parser = new UAParser(navigator.userAgent);
    const browserData = parser.getBrowser();
    const engineData = parser.getEngine();

    return {
      // Deterministic identifiers
      public_key_hash: await this.hashPublicKey(collectedData.deterministic?.public_key_pem),
      browser_installation_id: collectedData.deterministic?.browser_installation_id || '',
      cookie_device_id: collectedData.deterministic?.cookie_device_id || undefined,
      webauthn_credential_id: collectedData.deterministic?.webauthn_credential_id || undefined,

      // Browser
      browser: this.collectBrowserInfo(parser, browserData, engineData),

      // Display
      display: this.collectDisplayInfo(),

      // Locale
      locale: this.collectLocaleInfo(),

      // Fingerprint
      fingerprint: await this.collectFingerprintInfo(),

      // Security
      security_signals: this.collectSecuritySignals(),

      // Network
      network: this.collectNetworkInfo(),

      // App signals
      app_signals: this.collectAppSignals(),

      // Meta
      meta: {
        timestamp: Date.now()
      }
    };
  }

  /**
   * Hash public key using SHA-256
   */
  private static async hashPublicKey(publicKeyPem?: string | null): Promise<string | undefined> {
    if (!publicKeyPem) return undefined;

    const encoder = new TextEncoder();
    const data = encoder.encode(publicKeyPem);
    const hashBuffer = await crypto.subtle.digest('SHA-256', data);
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
  }

  /**
   * Collect browser information
   */
  private static collectBrowserInfo(parser: UAParser, browserData: any, engineData: any): BrowserInfo {
    return {
      user_agent: navigator.userAgent,
      browser_name: browserData.name || 'Unknown',
      browser_version_major: parseInt(browserData.major || '0'),
      engine_name: engineData.name || 'Unknown',
      engine_version: engineData.version || 'Unknown',
      platform: navigator.platform,
      vendor: navigator.vendor,
      cookie_enabled: navigator.cookieEnabled,
      do_not_track: navigator.doNotTrack === '1' ? true : navigator.doNotTrack === '0' ? false : null,
      languages: Array.from(navigator.languages || [navigator.language]),
      hardware_concurrency: navigator.hardwareConcurrency || 0,
      device_memory: (navigator as any).deviceMemory || undefined,
      max_touch_points: navigator.maxTouchPoints || 0
    };
  }

  /**
   * Collect display information
   */
  private static collectDisplayInfo(): DisplayInfo {
    return {
      screen: {
        width: screen.width,
        height: screen.height,
        avail_width: screen.availWidth,
        avail_height: screen.availHeight,
        color_depth: screen.colorDepth,
        device_pixel_ratio: window.devicePixelRatio || 1
      },
      viewport: {
        width: window.innerWidth,
        height: window.innerHeight
      }
    };
  }

  /**
   * Collect locale information
   */
  private static collectLocaleInfo(): LocaleInfo {
    const now = new Date();
    const timeZone = Intl.DateTimeFormat().resolvedOptions().timeZone;
    const offset = now.getTimezoneOffset() * -60; // Convert to seconds

    return {
      language: navigator.language,
      timezone: timeZone,
      timezone_offset: offset,
      hour_cycle_24h: this.is24HourFormat()
    };
  }

  /**
   * Detect 24-hour format
   */
  private static is24HourFormat(): boolean {
    const dateString = new Date().toLocaleTimeString();
    return !dateString.match(/AM|PM/i);
  }

  /**
   * Collect fingerprint information
   */
  private static async collectFingerprintInfo(): Promise<FingerprintInfo> {
    return {
      canvas_hash: await this.getCanvasHash(),
      webgl_vendor: this.getWebGLVendor(),
      webgl_renderer: this.getWebGLRenderer(),
      audio_hash: 'disabled-autoplay',
      font_hash: this.getFontHash(),
      media_devices_hash: await this.getMediaDevicesHash(),
      permissions_hash: await this.getPermissionsHash()
    };
  }

  /**
 * Collect fingerprint with audio (call after user interaction)
 */
  private static async collectFingerprintInfoWithAudio(): Promise<FingerprintInfo> {
    return {
      canvas_hash: await this.getCanvasHash(),
      webgl_vendor: this.getWebGLVendor(),
      webgl_renderer: this.getWebGLRenderer(),
      audio_hash: await this.getAudioHash(), // ✅ Include audio
      font_hash: this.getFontHash(),
      media_devices_hash: await this.getMediaDevicesHash(),
      permissions_hash: await this.getPermissionsHash()
    };
  }

  /**
   * Canvas fingerprint hash
   */
  private static async getCanvasHash(): Promise<string> {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return 'no-canvas';

    ctx.textBaseline = 'top';
    ctx.font = '14px Arial';
    ctx.fillStyle = '#f60';
    ctx.fillRect(125, 1, 62, 20);
    ctx.fillStyle = '#069';
    ctx.fillText('Browser Fingerprint', 2, 15);

    const dataURL = canvas.toDataURL();
    return this.hashString(dataURL);
  }

  /**
   * WebGL vendor
   */
  private static getWebGLVendor(): string {
    try {
      const canvas = document.createElement('canvas');
      const gl = canvas.getContext('webgl') || canvas.getContext('experimental-webgl');
      if (!gl) return 'no-webgl';

      const debugInfo = (gl as any).getExtension('WEBGL_debug_renderer_info');
      return debugInfo ? (gl as any).getParameter(debugInfo.UNMASKED_VENDOR_WEBGL) : 'unknown';
    } catch {
      return 'error';
    }
  }

  /**
   * WebGL renderer
   */
  private static getWebGLRenderer(): string {
    try {
      const canvas = document.createElement('canvas');
      const gl = canvas.getContext('webgl') || canvas.getContext('experimental-webgl');
      if (!gl) return 'no-webgl';

      const debugInfo = (gl as any).getExtension('WEBGL_debug_renderer_info');
      return debugInfo ? (gl as any).getParameter(debugInfo.UNMASKED_RENDERER_WEBGL) : 'unknown';
    } catch {
      return 'error';
    }
  }

  /**
   * Audio fingerprint hash
   */
  private static async getAudioHash(): Promise<string> {
    return new Promise((resolve) => {
      try {
        const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
        if (!AudioContext) {
          resolve('no-audio-context');
          return;
        }
        const context = new AudioContext();
        const oscillator = context.createOscillator();
        const analyser = context.createAnalyser();
        const gainNode = context.createGain();

        gainNode.gain.value = 0;

        oscillator.connect(analyser);
        analyser.connect(analyser);
        analyser.connect(gainNode);
        gainNode.connect(context.destination);

        // Configure analyser
        analyser.fftSize = 2048;
        const bufferLength = analyser.frequencyBinCount;
        const dataArray = new Uint8Array(bufferLength);

        oscillator.start(0);

        // Wait a bit then capture
        setTimeout(() => {
          analyser.getByteFrequencyData(dataArray);

          // Create hash from frequency data
          const hash = this.hashString(Array.from(dataArray).slice(0, 100).join(','));

          // Clean up
          try {
            oscillator.stop();
            context.close();
          } catch (e) {
            // Ignore cleanup errors
          }

          resolve(hash);
        }, 100);

        // Timeout fallback
        setTimeout(() => {
          try {
            oscillator.stop();
            context.close();
          } catch (e) {
            // Ignore
          }
          resolve('timeout');
        }, 1000);

      } catch {
        resolve('no-audio');
      }
    });
  }

  /**
   * Font list hash
   */
  private static getFontHash(): string {
    const baseFonts = ['monospace', 'sans-serif', 'serif'];
    const testFonts = [
      'Arial', 'Courier New', 'Georgia', 'Times New Roman', 'Verdana',
      'Helvetica', 'Comic Sans MS', 'Trebuchet MS', 'Impact'
    ];

    const detected: string[] = [];
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d')!;

    for (const font of testFonts) {
      for (const baseFont of baseFonts) {
        ctx.font = `72px ${baseFont}`;
        const baseWidth = ctx.measureText('mmmmmmmmmmlli').width;

        ctx.font = `72px ${font}, ${baseFont}`;
        const testWidth = ctx.measureText('mmmmmmmmmmlli').width;

        if (baseWidth !== testWidth) {
          detected.push(font);
          break;
        }
      }
    }

    return this.hashString(detected.join(','));
  }

  /**
   * Media devices hash
   */
  private static async getMediaDevicesHash(): Promise<string> {
    try {
      if (!navigator.mediaDevices) return 'no-media-devices';

      const devices = await navigator.mediaDevices.enumerateDevices();
      const deviceInfo = devices.map(d => `${d.kind}:${d.groupId}`).join(',');
      return this.hashString(deviceInfo);
    } catch {
      return 'error';
    }
  }

  /**
   * Permissions hash
   */
  private static async getPermissionsHash(): Promise<string> {
    try {
      if (!navigator.permissions) return 'no-permissions-api';

      const permissionsToCheck = ['geolocation', 'notifications', 'camera', 'microphone'];
      const results: string[] = [];

      for (const permission of permissionsToCheck) {
        try {
          const result = await navigator.permissions.query({ name: permission as PermissionName });
          results.push(`${permission}:${result.state}`);
        } catch {
          // Permission not supported
        }
      }

      return this.hashString(results.join(','));
    } catch {
      return 'error';
    }
  }

  /**
   * Collect security signals
   */
  private static collectSecuritySignals(): SecuritySignals {
    return {
      webdriver: !!navigator.webdriver,
      headless_detected: this.detectHeadless(),
      devtools_open: this.detectDevTools(),
      tamper_detected: this.detectTampering(),
      automation_detected: this.detectAutomation(),
      storage_disabled: !this.isStorageAvailable()
    };
  }

  /**
   * Detect headless browser
   */
  private static detectHeadless(): boolean {
    const checks = [
      !navigator.plugins.length,
      !(navigator as any).webdriver,
      navigator.userAgent.includes('HeadlessChrome'),
      !(window as any).chrome
    ];
    return checks.filter(Boolean).length >= 2;
  }

  /**
   * Detect DevTools
   */
  private static detectDevTools(): boolean {
    const threshold = 160;
    return window.outerWidth - window.innerWidth > threshold ||
      window.outerHeight - window.innerHeight > threshold;
  }

  /**
   * Detect tampering
   */
  private static detectTampering(): boolean {
    return (
      typeof navigator.plugins === 'undefined' ||
      typeof Function.prototype.bind === 'undefined'
    );
  }

  /**
   * Detect automation
   */
  private static detectAutomation(): boolean {
    return !!(window as any).__webdriver_script_fn ||
      !!(window as any)._Selenium_IDE_Recorder ||
      !!(window as any).callPhantom ||
      !!(window as any)._phantom;
  }

  /**
   * Check storage availability
   */
  private static isStorageAvailable(): boolean {
    try {
      localStorage.setItem('test', 'test');
      localStorage.removeItem('test');
      return true;
    } catch {
      return false;
    }
  }

  /**
   * Collect network information
   */
  private static collectNetworkInfo(): NetworkInfo {
    const connection = (navigator as any).connection || (navigator as any).mozConnection || (navigator as any).webkitConnection;

    return {
      network_type: this.getNetworkType(connection),
      vpn_suspected: false, // Cannot reliably detect on web
      proxy_suspected: false, // Cannot reliably detect on web
      effective_type: connection?.effectiveType || undefined,
      rtt: connection?.rtt || undefined,
      downlink: connection?.downlink || undefined
    };
  }

  /**
   * Get network type
   */
  private static getNetworkType(connection: any): string {
    if (!connection) return 'unknown';

    const type = connection.type;
    if (type) return type;

    const effectiveType = connection.effectiveType;
    if (effectiveType) {
      if (effectiveType === '4g') return 'cellular';
      if (['3g', '2g', 'slow-2g'].includes(effectiveType)) return 'cellular';
    }

    return 'unknown';
  }

  /**
   * Collect app signals
   */
  private static collectAppSignals(): AppSignals {
    return {
      sdk_version: '1.0.0', // From package.json
      script_integrity_hash: this.getScriptIntegrityHash(),
      origin: window.location.origin
    };
  }

  /**
   * Get script integrity hash
   */
  private static getScriptIntegrityHash(): string {
    const scripts = Array.from(document.getElementsByTagName('script'));
    const sdkScript = scripts.find(s => s.src.includes('dfp-sdk'));
    return sdkScript?.integrity || this.hashString(sdkScript?.src || 'no-sdk-script');
  }

  /**
   * Simple string hash (non-cryptographic)
   */
  private static hashString(str: string): string {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
      const char = str.charCodeAt(i);
      hash = ((hash << 5) - hash) + char;
      hash = hash & hash;
    }
    return Math.abs(hash).toString(16);
  }
}