import { AbstractCollector } from './base-collector';


export interface NetworkCollectorData {
  effectiveType?: string;
  downlink?: number;
  rtt?: number;
  saveData?: boolean;
  type?: string;
}
export class NetworkCollector extends AbstractCollector<NetworkCollectorData> {
  isAvailable(): boolean {
    return 'connection' in navigator;
  }

  collect(): NetworkCollectorData {
    if (!this.isAvailable()) {
      return {};
    }

    const connection = (navigator as any).connection ||
      (navigator as any).mozConnection ||
      (navigator as any).webkitConnection;
    return this.handleError(() => ({
      effectiveType: connection?.effectiveType,
      downlink: connection?.downlink,
      rtt: connection?.rtt,
      saveData: connection?.saveData,
      type: connection?.type
    }), {
      effectiveType: undefined,
      downlink: undefined,
      rtt: undefined,
      saveData: undefined,
      type: undefined
    });
  }
}

export function collectNetwork(): NetworkCollectorData {
  const collector = new NetworkCollector();
  return collector.collect();
}