import { AbstractCollector } from "../base-collector";

export class CookieDeviceCollector extends AbstractCollector<string | null> {
  isAvailable(): boolean {
    return typeof document !== 'undefined' && typeof document.cookie !== 'undefined';
  }
  getRequiredFields(): string[] {
    throw new Error("Method not implemented.");
  }
  private readonly COOKIE_NAME = 'device_id';

  collect(): string | null {
    try {
      const cookies = document.cookie.split(';')
      for (const cookie of cookies) {
        const [name, value] = cookie.trim().split('=');
        if (name === this.COOKIE_NAME) {
          return decodeURIComponent(value);
        }
      }
      return null;
    } catch (error) {
      console.warn('Failed to access cookies:', error);
      return null;
    }
  }

  setCookie(deviceId: string, days: number = 365): void {
    try {
      const expires = new Date(Date.now() + days * 24 * 60 * 60 * 1000).toUTCString();
      document.cookie = `${this.COOKIE_NAME}=${encodeURIComponent(deviceId)}; expires=${expires}; path=/;SameSite=Strict`;
    } catch (error) {
      console.warn('Failed to set cookie:', error);
    }
  }
}