import { AbstractCollector } from './base-collector';


export interface ScreenCollectorData {
  width: number;
  height: number;
  availWidth: number;
  availHeight: number;
  colorDepth: number;
  pixelDepth: number;
  devicePixelRatio: number;
  orientation?: string;
}


export class ScreenCollector extends AbstractCollector<ScreenCollectorData> {
  isAvailable(): boolean {
    return typeof screen !== 'undefined';
  }

  collect(): ScreenCollectorData {
    if (!this.isAvailable()) {
      throw new Error('Screen API not available');
    }

    return this.handleError(() => ({
      width: screen.width,
      height: screen.height,
      availWidth: screen.availWidth,
      availHeight: screen.availHeight,
      colorDepth: screen.colorDepth,
      pixelDepth: screen.pixelDepth,
      devicePixelRatio: window.devicePixelRatio || 1,
      orientation: screen.orientation?.type as OrientationType || 'landscape-primary'
    }), {
      height: 0,
      availWidth: 0,
      availHeight: 0,
      colorDepth: 0,
      pixelDepth: 0,
      devicePixelRatio: 1,
      orientation: 'landscape-primary',
      width: 0
    });
  }
}

export function collectScreen(): ScreenCollectorData {
  const collector = new ScreenCollector();
  return collector.collect();
}