import { AbstractCollector } from "../base-collector";
import { StorageManager } from "../../storage/storage-manager";
export class InstallationIdCollector extends AbstractCollector<string> {
  private readonly STORAGE_LEY = 'browser_installation_id';
  private storageManager: StorageManager;

  constructor(storageManager: StorageManager) {
    super();
    this.storageManager = storageManager;
  }
  isAvailable(): boolean {
    throw new Error("Method not implemented.");
  }

  async collect(): Promise<string> {
    try {
      let installationId = await this.storageManager.get(this.STORAGE_LEY);
      if (!installationId) {
        installationId = this.generateInstallationId();
        if (installationId) {
          await this.storageManager.set(this.STORAGE_LEY, installationId);
        }
      }
      return installationId;
    } catch (error) {
      return this.generateInstallationId() || '';
    }

  }
  private generateInstallationId(): string {
    const timestamp = Date.now();
    const random = crypto.getRandomValues(new Uint8Array(16));
    const randomHex = Array.from(random).map(b => b.toString(16).padStart(2, '0')).join('');
    return `${timestamp}-${randomHex}`;
  }
}