import { AbstractCollector } from './base-collector';

export interface BrowserCollectorData {
  userAgent: string;
  language: string;
  languages: string[];
  platform: string;
  vendor: string;
  cookieEnabled: boolean;
  doNotTrack: string | null;
  hardwareConcurrency: number;
  deviceMemory?: number;
  maxTouchPoints: number;
  pdfViewerEnabled: boolean;
}


export class BrowserCollector extends AbstractCollector<BrowserCollectorData> {
  isAvailable(): boolean {
    return typeof navigator !== 'undefined';
  }

  collect(): BrowserCollectorData {
    if (!this.isAvailable()) {
      throw new Error('Navigator not available');
    }

    const nav = navigator as any;
    return {
      userAgent: nav.userAgent ?? '',
      language: nav.language ?? '',
      languages: nav.languages ? Array.from(nav.languages) : [],
      platform: nav.platform ?? '',
      vendor: nav.vendor ?? '',
      cookieEnabled: nav.cookieEnabled ?? false,
      doNotTrack: nav.doNotTrack ?? null,
      hardwareConcurrency: nav.hardwareConcurrency ?? 0,
      deviceMemory: nav.deviceMemory ?? undefined,
      maxTouchPoints: nav.maxTouchPoints ?? 0,
      pdfViewerEnabled: nav.pdfViewerEnabled ?? false,
    };
  }
}

// Keep the function export for backward compatibility
export function collectBrowser(): BrowserCollectorData {
  const collector = new BrowserCollector();
  return collector.collect();
}